// Extract and normalize form data
const body = $input.all()[0].json.body || $input.all()[0].json;
return [{
  json: {
    lead_name: body.name || body.firstName + ' ' + (body.lastName || ''),
    lead_email: body.email || '',
    company_name: body.company || body.companyName || '',
    title: body.title || body.jobTitle || '',
    message: body.message || body.comments || '',
    source: 'website_form',
    received_at: new Date().toISOString()
  }
}];

// Merge lead data with enrichment, then call Claude for scoring
const lead = $('Normalize Form Data').first().json;
const enrichment = $input.all()[0].json;
const person = enrichment.person || {};
const org = person.organization || {};

return [{
  json: {
    ...lead,
    industry: org.industry || 'Unknown',
    employee_count: org.estimated_num_employees || 'Unknown',
    estimated_arr: org.annual_revenue_printed || 'Unknown',
    funding_stage: org.latest_funding_stage || 'Unknown',
    tech_stack: (person.organization?.current_technologies || []).join(', ') || 'Unknown',
    recent_news: '',
    website: org.website_url || ''
  }
}];

