// Parse Claude scoring and prepare outputs
const scoring = $input.all()[0].json;
const lead = $('Merge Enrichment Data').first().json;
const parsed = typeof scoring.parsed_content === 'string' 
  ? JSON.parse(scoring.parsed_content) 
  : scoring.parsed_content;

return [{
  json: {
    ...lead,
    ...parsed,
    is_hot: parsed.tier === 'Hot'
  }
}];
